  describe('create', () => {
    it('should create a new cycle with valid data', async () => {
      const cycleData = TestFactory.cycleCreate({
        name: 'Sprint 1',
        teamId: 'team-123',
        startsAt: '2024-01-01T00:00:00Z',
        endsAt: '2024-01-14T00:00:00Z',
      });

      const mockCycle = createMockCycle({ 
        id: 'cycle-123', 
