      mockClient.createCycle.mockResolvedValue(
        createMockPayload(true, mockCycle)
      );

      const result = await service.create(cycleData);

      expect(mockClient.createCycle).toHaveBeenCalledWith({
        name: cycleData.name,
        teamId: cycleData.teamId,
        startsAt: cycleData.startsAt,
        endsAt: cycleData.endsAt,
