      const activeCycle = createMockCycle({
        id: 'cycle-active',
        startsAt: new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString(),
        endsAt: new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000).toISOString(),
        teamId: 'team-123'
