  describe('list', () => {
    it('should list cycles with filters', async () => {
      const mockCycles = [
        createMockCycle({ id: '1' }),
        createMockCycle({ id: '2' }),
      ];
      mockClient.cycles.mockResolvedValue(
        createMockCycleConnection(mockCycles)
      );

      const filter = TestFactory.cycleFilter({
        teamId: 'team-123',
        isActive: true,
      });

