    it('should return null when only past cycles exist', async () => {
      const now = new Date();
      const pastCycle = createMockCycle({
        startsAt: new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000).toISOString(),
        endsAt: new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString(),
        teamId: 'team-123'
