import { 
  Cycle, 
  CycleConnection,
  Issue,
  IssueConnection,
  LinearDocument
} from '@linear/sdk';

type CycleCreateInput = LinearDocument.CycleCreateInput;
type CycleUpdateInput = LinearDocument.CycleUpdateInput;
type LinearCycleFilter = LinearDocument.CycleFilter;
type LinearIssueFilter = LinearDocument.IssueFilter;

import { linearClient } from '@atoms/client/linear-client';
import { logger } from '@atoms/shared/logger';
import { 
  NotFoundError, 
  ValidationError,
  Pagination 
} from '@atoms/types/common';
import { 
  CycleCreate, 
  CycleUpdate, 
  CycleFilter,
  CycleProgress
} from './schemas';
import { IssueFilter } from '@features/issue/schemas';

export class CycleService {
  private client = linearClient.getClient();

  async create(data: CycleCreate): Promise<Cycle> {
    try {
      logger.debug('Creating cycle', data);

      // Check for overlapping cycles within the same team
      await this.validateNonOverlapping(data.teamId, data.startsAt, data.endsAt);

      const input: CycleCreateInput = {
        name: data.name,
        teamId: data.teamId,
        startsAt: new Date(data.startsAt),
        endsAt: new Date(data.endsAt),
        description: data.description,
      };

      const payload = await this.client.createCycle(input);

      if (!payload.success || !payload.cycle) {
        throw new ValidationError('Failed to create cycle');
      }

      const cycle = await payload.cycle;
      logger.success(`Cycle created: ${cycle.name}`);

      return cycle;
    } catch (error) {
      logger.error('Failed to create cycle', error);
      throw error;
    }
  }

  async get(id: string): Promise<Cycle | null> {
    try {
      logger.debug(`Fetching cycle: ${id}`);
      const cycle = await this.client.cycle(id);
      return cycle;
    } catch (error) {
      logger.debug(`Cycle not found: ${id}`);
      return null;
    }
  }

  async update(id: string, data: CycleUpdate): Promise<Cycle> {
    try {
      logger.debug(`Updating cycle: ${id}`, data);

      const cycle = await this.get(id);
      if (!cycle) {
        throw new NotFoundError('Cycle', id);
      }

      // If updating dates, check for overlapping cycles
      if (data.startsAt || data.endsAt) {
        const startDate = data.startsAt || cycle.startsAt.toISOString();
        const endDate = data.endsAt || cycle.endsAt.toISOString();
        const team = cycle.team ? await cycle.team : null;
        if (!team) {
          throw new NotFoundError('Team for cycle', id);
        }

        await this.validateNonOverlapping(team.id, startDate, endDate, id);
      }

      const input: CycleUpdateInput = {
        name: data.name,
        description: data.description,
        startsAt: data.startsAt ? new Date(data.startsAt) : undefined,
        endsAt: data.endsAt ? new Date(data.endsAt) : undefined,
      };

      const payload = await this.client.updateCycle(id, input);

      if (!payload.success || !payload.cycle) {
        throw new ValidationError('Failed to update cycle');
      }

      const updatedCycle = await payload.cycle;
      logger.success(`Cycle updated: ${updatedCycle.name}`);

      return updatedCycle;
    } catch (error) {
      logger.error(`Failed to update cycle ${id}`, error);
      throw error;
    }
  }

  async archive(id: string): Promise<boolean> {
    try {
      logger.debug(`Archiving cycle: ${id}`);

      const cycle = await this.get(id);
      if (!cycle) {
        throw new NotFoundError('Cycle', id);
      }

      const payload = await this.client.archiveCycle(id);

      if (!payload.success) {
        throw new ValidationError('Failed to archive cycle');
      }

      logger.success(`Cycle archived: ${id}`);
      return true;
    } catch (error) {
      logger.error(`Failed to archive cycle ${id}`, error);
      throw error;
    }
  }

  async list(filter?: CycleFilter, pagination?: Pagination): Promise<CycleConnection> {
    try {
      logger.debug('Listing cycles', { filter, pagination });

      const linearFilter: LinearCycleFilter = {};

      if (filter) {
        if (filter.teamId) {
          linearFilter.team = { id: { eq: filter.teamId } };
        }
      }

      const cycles = await this.client.cycles({
        filter: linearFilter,
        includeArchived: filter?.includeArchived,
        first: pagination?.first,
        after: pagination?.after,
        before: pagination?.before,
        last: pagination?.last,
      });

      return cycles;
    } catch (error) {
      logger.error('Failed to list cycles', error);
      throw error;
    }
  }

  async getActive(teamId: string): Promise<Cycle | null> {
    try {
      logger.debug(`Getting active cycle for team: ${teamId}`);

      const cycles = await this.client.cycles({
        filter: {
          team: { id: { eq: teamId } },
        },
        includeArchived: false,
      });

      const cycleNodes = await cycles.nodes;
      const now = new Date();

      // Find cycle where current time is between start and end dates
      const activeCycle = cycleNodes.find(cycle => {
        const startDate = new Date(cycle.startsAt);
        const endDate = new Date(cycle.endsAt);
        return now >= startDate && now <= endDate;
      });

      return activeCycle || null;
    } catch (error) {
      logger.error(`Failed to get active cycle for team ${teamId}`, error);
      throw error;
    }
  }

  async getUpcoming(teamId: string): Promise<CycleConnection> {
    try {
      logger.debug(`Getting upcoming cycles for team: ${teamId}`);

      const cycles = await this.client.cycles({
        filter: {
          team: { id: { eq: teamId } },
        },
        includeArchived: false,
      });

      const cycleNodes = await cycles.nodes;
      const now = new Date();

      // Filter cycles that start in the future
      const upcomingCycles = cycleNodes.filter(cycle => {
        const startDate = new Date(cycle.startsAt);
        return startDate > now;
      });

      // Return as connection format (simplified mock for now)
      return {
        ...cycles,
        nodes: upcomingCycles,
      } as CycleConnection;
    } catch (error) {
      logger.error(`Failed to get upcoming cycles for team ${teamId}`, error);
      throw error;
    }
  }

  async getCompleted(teamId: string): Promise<CycleConnection> {
    try {
      logger.debug(`Getting completed cycles for team: ${teamId}`);

      const cycles = await this.client.cycles({
        filter: {
          team: { id: { eq: teamId } },
        },
        includeArchived: false,
      });

      const cycleNodes = await cycles.nodes;

      // Filter cycles that have a completedAt date
      const completedCycles = cycleNodes.filter(cycle => cycle.completedAt);

      // Return as connection format (simplified mock for now)
      return {
        ...cycles,
        nodes: completedCycles,
      } as CycleConnection;
    } catch (error) {
      logger.error(`Failed to get completed cycles for team ${teamId}`, error);
      throw error;
    }
  }

  async getIssues(cycleId: string, filter?: IssueFilter): Promise<IssueConnection> {
    try {
      logger.debug(`Getting issues for cycle: ${cycleId}`);

      const linearFilter: LinearIssueFilter = {
        cycle: { id: { eq: cycleId } },
      };

      if (filter) {
        if (filter.state) {
          linearFilter.state = { type: { eq: filter.state } };
        }
        if (filter.assigneeId) {
          linearFilter.assignee = { id: { eq: filter.assigneeId } };
        }
      }

      const issues = await this.client.issues({
        filter: linearFilter,
        includeArchived: false,
      });

      return issues;
    } catch (error) {
      logger.error(`Failed to get issues for cycle ${cycleId}`, error);
      throw error;
    }
  }

  async addIssue(cycleId: string, issueId: string): Promise<Issue> {
    try {
      logger.debug(`Adding issue ${issueId} to cycle ${cycleId}`);

      const issue = await this.client.issue(issueId);
      if (!issue) {
        throw new NotFoundError('Issue', issueId);
      }

      const payload = await this.client.updateIssue(issueId, {
        cycleId: cycleId,
      });

      if (!payload.success || !payload.issue) {
        throw new ValidationError('Failed to add issue to cycle');
      }

      const updatedIssue = await payload.issue;
      logger.success(`Issue added to cycle: ${updatedIssue.identifier}`);

      return updatedIssue;
    } catch (error) {
      logger.error(`Failed to add issue ${issueId} to cycle ${cycleId}`, error);
      throw error;
    }
  }

  async removeIssue(cycleId: string, issueId: string): Promise<Issue> {
    try {
      logger.debug(`Removing issue ${issueId} from cycle ${cycleId}`);

      const issue = await this.client.issue(issueId);
      if (!issue) {
        throw new NotFoundError('Issue', issueId);
      }

      const payload = await this.client.updateIssue(issueId, {
        cycleId: null,
      });

      if (!payload.success || !payload.issue) {
        throw new ValidationError('Failed to remove issue from cycle');
      }

      const updatedIssue = await payload.issue;
      logger.success(`Issue removed from cycle: ${updatedIssue.identifier}`);

      return updatedIssue;
    } catch (error) {
      logger.error(`Failed to remove issue ${issueId} from cycle ${cycleId}`, error);
      throw error;
    }
  }

  async getProgress(cycleId: string): Promise<CycleProgress> {
    try {
      logger.debug(`Calculating progress for cycle: ${cycleId}`);

      const cycle = await this.get(cycleId);
      if (!cycle) {
        throw new NotFoundError('Cycle', cycleId);
      }

      const issues = await this.getIssues(cycleId);
      const issueNodes = await issues.nodes;

      let completedPoints = 0;
      let totalPoints = 0;
      let completedIssues = 0;
      const totalIssues = issueNodes.length;

      for (const issue of issueNodes) {
        const estimate = issue.estimate || 0;
        totalPoints += estimate;

        if (issue.completedAt) {
          completedPoints += estimate;
          completedIssues++;
        }
      }

      const percentComplete = totalPoints > 0 ? Math.round((completedPoints / totalPoints) * 100) : 0;

      return {
        completedPoints,
        totalPoints,
        percentComplete,
        completedIssues,
        totalIssues,
      };
    } catch (error) {
      logger.error(`Failed to calculate progress for cycle ${cycleId}`, error);
      throw error;
    }
  }

  async getVelocity(cycleId: string): Promise<number> {
    try {
      logger.debug(`Calculating velocity for cycle: ${cycleId}`);

      const cycle = await this.get(cycleId);
      if (!cycle) {
        throw new NotFoundError('Cycle', cycleId);
      }

      const issues = await this.getIssues(cycleId);
      const issueNodes = await issues.nodes;

      let completedPoints = 0;
      for (const issue of issueNodes) {
        if (issue.completedAt && issue.estimate) {
          completedPoints += issue.estimate;
        }
      }

      // Calculate cycle duration in weeks
      const startDate = new Date(cycle.startsAt);
      const endDate = new Date(cycle.endsAt);
      const durationMs = endDate.getTime() - startDate.getTime();
      const durationWeeks = durationMs / (1000 * 60 * 60 * 24 * 7);

      // Velocity = completed points per week
      const velocity = durationWeeks > 0 ? completedPoints / durationWeeks : 0;

      return velocity;
    } catch (error) {
      logger.error(`Failed to calculate velocity for cycle ${cycleId}`, error);
      throw error;
    }
  }

  private async validateNonOverlapping(teamId: string, startsAt: string, endsAt: string, excludeCycleId?: string): Promise<void> {
    const existingCycles = await this.client.cycles({
      filter: {
        team: { id: { eq: teamId } },
      },
      includeArchived: false,
    });

    const cycleNodes = await existingCycles.nodes;
    const newStart = new Date(startsAt);
    const newEnd = new Date(endsAt);

    for (const cycle of cycleNodes) {
      if (excludeCycleId && cycle.id === excludeCycleId) {
        continue; // Skip the cycle being updated
      }

      const existingStart = new Date(cycle.startsAt);
      const existingEnd = new Date(cycle.endsAt);

      // Check for overlap: new cycle starts before existing ends AND new cycle ends after existing starts
      const hasOverlap = newStart < existingEnd && newEnd > existingStart;

      if (hasOverlap) {
        throw new ValidationError(`Cycle dates overlap with existing cycle: ${cycle.name}`);
      }
    }
  }
}

import { CommentService } from '@features/comment/service';
import { linearClient } from '@atoms/client/linear-client';
import { NotFoundError, ValidationError } from '@atoms/types/common';
import { TestFactory } from '../fixtures/factories';
import { 
  createMockComment,
  createMockPayload,
  createMockConnection,
  createMockLinearClient,
  createMockUser
} from '../utils/mocks';

jest.mock('@atoms/client/linear-client');

describe('CommentService', () => {
  let service: CommentService;
  let mockClient: ReturnType<typeof createMockLinearClient>;

  beforeEach(() => {
    TestFactory.reset();
    mockClient = createMockLinearClient();
    (linearClient.getClient as jest.Mock).mockReturnValue(mockClient);
    service = new CommentService();
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('create', () => {
    it('should create a comment on an issue successfully', async () => {
      const commentData = {
        issueId: 'issue-123',
        body: 'This is a test comment',
      };
      const mockComment = createMockComment({
        id: 'comment-123',
        ...commentData,
        __typename: 'Comment'
      });

      mockClient.createComment.mockResolvedValue(
        createMockPayload(true, mockComment)
      );

      const result = await service.create(commentData);

      expect(mockClient.createComment).toHaveBeenCalledWith(
        expect.objectContaining({
          issueId: 'issue-123',
          body: 'This is a test comment',
        })
      );
      expect(result.id).toBe('comment-123');
      expect(result.body).toBe('This is a test comment');
    });

    it('should support markdown formatting in comments', async () => {
      const commentData = {
        issueId: 'issue-123',
        body: '**Bold** and *italic* with [link](http://example.com)',
      };
      const mockComment = createMockComment({
        id: 'comment-123',
        ...commentData,
        __typename: 'Comment'
      });

      mockClient.createComment.mockResolvedValue(
        createMockPayload(true, mockComment)
      );

      const result = await service.create(commentData);

      expect(result.body).toContain('**Bold**');
      expect(result.body).toContain('[link]');
    });

    it('should create threaded reply when parentId provided', async () => {
      const replyData = {
        issueId: 'issue-123',
        body: 'This is a reply',
        parentId: 'comment-parent',
      };
      const mockReply = createMockComment({
        id: 'comment-reply',
        ...replyData,
        __typename: 'Comment'
      });

      mockClient.createComment.mockResolvedValue(
        createMockPayload(true, mockReply)
      );

      const result = await service.create(replyData);

      expect(mockClient.createComment).toHaveBeenCalledWith(
        expect.objectContaining({
          issueId: 'issue-123',
          body: 'This is a reply',
          parentId: 'comment-parent',
        })
      );
      // Comment includes the parentId in the creation data
      expect(result.body).toBe('This is a reply');
    });

    it('should handle optional createAsUser field', async () => {
      const commentData = {
        issueId: 'issue-123',
        body: 'Comment created as another user',
        createAsUser: 'user-456',
      };
      const mockComment = createMockComment({
        id: 'comment-123',
        ...commentData,
        __typename: 'Comment'
      });

      mockClient.createComment.mockResolvedValue(
        createMockPayload(true, mockComment)
      );

      await service.create(commentData);

      expect(mockClient.createComment).toHaveBeenCalledWith(
        expect.objectContaining({
          createAsUser: 'user-456',
        })
      );
    });

    it('should handle optional displayIconUrl field', async () => {
      const commentData = {
        issueId: 'issue-123',
        body: 'Comment with custom icon',
        displayIconUrl: 'https://example.com/icon.png',
      };
      const mockComment = createMockComment({
        id: 'comment-123',
        ...commentData,
        __typename: 'Comment'
      });

      mockClient.createComment.mockResolvedValue(
        createMockPayload(true, mockComment)
      );

      await service.create(commentData);

      expect(mockClient.createComment).toHaveBeenCalledWith(
        expect.objectContaining({
          displayIconUrl: 'https://example.com/icon.png',
        })
      );
    });

    it('should throw ValidationError when creation fails', async () => {
      const commentData = {
        issueId: 'issue-123',
        body: 'Test comment',
      };

      mockClient.createComment.mockResolvedValue(
        createMockPayload(false)
      );

      await expect(service.create(commentData)).rejects.toThrow(ValidationError);
    });

    it('should validate required fields', async () => {
      await expect(service.create({
        issueId: '',
        body: 'Test comment',
      })).rejects.toThrow(ValidationError);

      await expect(service.create({
        issueId: 'issue-123',
        body: '',
      })).rejects.toThrow(ValidationError);
    });

    it('should validate displayIconUrl format when provided', async () => {
      await expect(service.create({
        issueId: 'issue-123',
        body: 'Test comment',
        displayIconUrl: 'invalid-url',
      })).rejects.toThrow(ValidationError);
    });
  });

  describe('get', () => {
    it('should return a comment when found', async () => {
      const mockComment = createMockComment({ id: 'comment-123' });
      mockClient.comment = jest.fn().mockResolvedValue(mockComment);

      const result = await service.get('comment-123');

      expect(mockClient.comment).toHaveBeenCalledWith('comment-123');
      expect(result).toEqual(mockComment);
    });

    it('should return null when comment not found', async () => {
      mockClient.comment = jest.fn().mockRejectedValue(new Error('Not found'));

      const result = await service.get('nonexistent');

      expect(result).toBeNull();
    });
  });

  describe('update', () => {
    it('should update comment body successfully', async () => {
      const mockComment = createMockComment({ id: 'comment-123' });
      const updateData = { body: 'Updated comment text' };
      const updatedComment = createMockComment({
        id: 'comment-123',
        body: 'Updated comment text',
        edited: true,
        __typename: 'Comment'
      });

      mockClient.comment = jest.fn().mockResolvedValue(mockComment);
      mockClient.updateComment = jest.fn().mockResolvedValue(
        createMockPayload(true, updatedComment)
      );

      const result = await service.update('comment-123', updateData);

      expect(mockClient.updateComment).toHaveBeenCalledWith(
        'comment-123',
        expect.objectContaining({
          body: 'Updated comment text',
        })
      );
      expect(result.body).toBe('Updated comment text');
      expect(result.editedAt).toBeDefined();
    });

    it('should throw NotFoundError when comment does not exist', async () => {
      mockClient.comment = jest.fn().mockRejectedValue(new Error('Not found'));

      await expect(
        service.update('nonexistent', { body: 'Updated text' })
      ).rejects.toThrow(NotFoundError);
    });

    it('should throw ValidationError when update fails', async () => {
      const mockComment = createMockComment({ id: 'comment-123' });
      mockClient.comment = jest.fn().mockResolvedValue(mockComment);
      mockClient.updateComment = jest.fn().mockResolvedValue(
        createMockPayload(false)
      );

      await expect(
        service.update('comment-123', { body: 'Updated text' })
      ).rejects.toThrow(ValidationError);
    });

    it('should validate update data', async () => {
      await expect(
        service.update('comment-123', { body: '' })
      ).rejects.toThrow(ValidationError);
    });
  });

  describe('delete', () => {
    it('should delete a comment successfully', async () => {
      const mockComment = createMockComment({ id: 'comment-123' });
      mockClient.comment = jest.fn().mockResolvedValue(mockComment);
      mockClient.deleteComment = jest.fn().mockResolvedValue(
        createMockPayload(true)
      );

      const result = await service.delete('comment-123');

      expect(mockClient.deleteComment).toHaveBeenCalledWith('comment-123');
      expect(result).toBe(true);
    });

    it('should throw NotFoundError when comment does not exist', async () => {
      mockClient.comment = jest.fn().mockRejectedValue(new Error('Not found'));

      await expect(service.delete('nonexistent')).rejects.toThrow(NotFoundError);
    });

    it('should return false when deletion fails', async () => {
      const mockComment = createMockComment({ id: 'comment-123' });
      mockClient.comment = jest.fn().mockResolvedValue(mockComment);
      mockClient.deleteComment = jest.fn().mockResolvedValue(
        createMockPayload(false)
      );

      const result = await service.delete('comment-123');

      expect(result).toBe(false);
    });
  });

  describe('listByIssue', () => {
    it('should list comments for an issue', async () => {
      const mockComments = [
        createMockComment({ id: 'comment-1', body: 'First comment' }),
        createMockComment({ id: 'comment-2', body: 'Second comment' }),
      ];
      const mockConnection = createMockConnection(mockComments);

      mockClient.comments = jest.fn().mockResolvedValue(mockConnection);

      const result = await service.listByIssue('issue-123');

      expect(mockClient.comments).toHaveBeenCalledWith({
        filter: {
          issue: { id: { eq: 'issue-123' } }
        },
        first: 50,
      });
      expect(result.nodes).toEqual(mockComments);
    });

    it('should handle pagination parameters for issue comments', async () => {
      mockClient.comments = jest.fn().mockResolvedValue(
        createMockConnection([])
      );

      await service.listByIssue('issue-123', { first: 20, after: 'cursor-123' });

      expect(mockClient.comments).toHaveBeenCalledWith({
        filter: {
          issue: { id: { eq: 'issue-123' } }
        },
        first: 20,
        after: 'cursor-123',
      });
    });
  });

  describe('listByUser', () => {
    it('should list comments by a user', async () => {
      const mockComments = [
        createMockComment({ id: 'comment-1', body: 'User comment 1' }),
        createMockComment({ id: 'comment-2', body: 'User comment 2' }),
      ];
      const mockConnection = createMockConnection(mockComments);

      mockClient.comments = jest.fn().mockResolvedValue(mockConnection);

      const result = await service.listByUser('user-123');

      expect(mockClient.comments).toHaveBeenCalledWith({
        filter: {
          user: { id: { eq: 'user-123' } }
        },
        first: 50,
      });
      expect(result.nodes).toEqual(mockComments);
    });

    it('should handle pagination parameters for user comments', async () => {
      mockClient.comments = jest.fn().mockResolvedValue(
        createMockConnection([])
      );

      await service.listByUser('user-123', { first: 30, after: 'cursor-456' });

      expect(mockClient.comments).toHaveBeenCalledWith({
        filter: {
          user: { id: { eq: 'user-123' } }
        },
        first: 30,
        after: 'cursor-456',
      });
    });
  });

  describe('createReaction', () => {
    it('should add valid emoji reaction to comment', async () => {
      const mockReaction = {
        id: 'reaction-123',
        emoji: '👍',
        __typename: 'Reaction'
      };

      mockClient.createReaction = jest.fn().mockResolvedValue(
        createMockPayload(true, mockReaction)
      );

      const result = await service.createReaction('comment-123', '👍');

      expect(mockClient.createReaction).toHaveBeenCalledWith({
        commentId: 'comment-123',
        emoji: '👍',
      });
      expect(result.emoji).toBe('👍');
    });

    it('should support all valid emoji reactions', async () => {
      const validEmojis = ['👍', '👎', '❤️', '🎉', '👀'];

      for (const emoji of validEmojis) {
        const mockReaction = {
          id: `reaction-${emoji}`,
          emoji,
          __typename: 'Reaction'
        };

        mockClient.createReaction = jest.fn().mockResolvedValue(
          createMockPayload(true, mockReaction)
        );

        const result = await service.createReaction('comment-123', emoji);
        expect(result.emoji).toBe(emoji);
      }
    });

    it('should throw ValidationError for invalid emoji reactions', async () => {
      const invalidEmojis = ['🚀', '💀', '🤔', 'invalid', ''];

      for (const emoji of invalidEmojis) {
        await expect(
          service.createReaction('comment-123', emoji)
        ).rejects.toThrow(ValidationError);
      }
    });

    it('should throw ValidationError when reaction creation fails', async () => {
      mockClient.createReaction = jest.fn().mockResolvedValue(
        createMockPayload(false)
      );

      await expect(
        service.createReaction('comment-123', '👍')
      ).rejects.toThrow(ValidationError);
    });
  });

  describe('deleteReaction', () => {
    it('should delete a reaction successfully', async () => {
      mockClient.deleteReaction = jest.fn().mockResolvedValue(
        createMockPayload(true)
      );

      const result = await service.deleteReaction('reaction-123');

      expect(mockClient.deleteReaction).toHaveBeenCalledWith('reaction-123');
      expect(result).toBe(true);
    });

    it('should return false when reaction deletion fails', async () => {
      mockClient.deleteReaction = jest.fn().mockResolvedValue(
        createMockPayload(false)
      );

      const result = await service.deleteReaction('reaction-123');

      expect(result).toBe(false);
    });

    it('should handle non-existent reaction gracefully', async () => {
      mockClient.deleteReaction = jest.fn().mockRejectedValue(
        new Error('Reaction not found')
      );

      const result = await service.deleteReaction('nonexistent');

      expect(result).toBe(false);
    });
  });

  describe('getReplies', () => {
    it('should get replies to a comment', async () => {
      const mockReplies = [
        createMockComment({ id: 'reply-1', parentId: 'comment-123' }),
        createMockComment({ id: 'reply-2', parentId: 'comment-123' }),
      ];
      const mockConnection = createMockConnection(mockReplies);

      mockClient.comments = jest.fn().mockResolvedValue(mockConnection);

      const result = await service.getReplies('comment-123');

      expect(mockClient.comments).toHaveBeenCalledWith({
        filter: {
          parent: { id: { eq: 'comment-123' } }
        },
        first: 50,
      });
      expect(result.nodes).toEqual(mockReplies);
    });

    it('should handle pagination for replies', async () => {
      mockClient.comments = jest.fn().mockResolvedValue(
        createMockConnection([])
      );

      await service.getReplies('comment-123', { first: 25, after: 'cursor-789' });

      expect(mockClient.comments).toHaveBeenCalledWith({
        filter: {
          parent: { id: { eq: 'comment-123' } }
        },
        first: 25,
        after: 'cursor-789',
      });
    });
  });

  describe('getParent', () => {
    it('should return parent comment when it exists', async () => {
      const childComment = createMockComment({
        id: 'comment-child',
        parentId: 'comment-parent'
      });
      const parentComment = createMockComment({ id: 'comment-parent' });

      mockClient.comment = jest.fn()
        .mockResolvedValueOnce(childComment)
        .mockResolvedValueOnce(parentComment);

      const result = await service.getParent('comment-child');

      expect(mockClient.comment).toHaveBeenCalledWith('comment-child');
      expect(mockClient.comment).toHaveBeenCalledWith('comment-parent');
      expect(result).toEqual(parentComment);
    });

    it('should return null when comment has no parent', async () => {
      const topLevelComment = createMockComment({
        id: 'comment-123',
      });
      // Mock parent to return null
      topLevelComment.parent = jest.fn().mockResolvedValue(null);

      mockClient.comment = jest.fn().mockResolvedValue(topLevelComment);

      const result = await service.getParent('comment-123');

      expect(mockClient.comment).toHaveBeenCalledWith('comment-123');
      expect(result).toBeNull();
    });

    it('should return null when comment does not exist', async () => {
      mockClient.comment = jest.fn().mockRejectedValue(new Error('Not found'));

      const result = await service.getParent('nonexistent');

      expect(result).toBeNull();
    });

    it('should return null when parent comment does not exist', async () => {
      const childComment = createMockComment({
        id: 'comment-child',
        parentId: 'nonexistent-parent'
      });

      mockClient.comment = jest.fn()
        .mockResolvedValueOnce(childComment)
        .mockRejectedValueOnce(new Error('Parent not found'));

      const result = await service.getParent('comment-child');

      expect(result).toBeNull();
    });
  });

  describe('parseMentions', () => {
    it('should extract user mentions from comment body', () => {
      const body = 'Hey @john, can you review this? Also @jane needs to see this.';
      const mentions = service.parseMentions(body);

      expect(mentions.users).toEqual(['john', 'jane']);
      expect(mentions.issues).toEqual([]);
    });

    it('should extract issue mentions from comment body', () => {
      const body = 'This relates to #ENG-123 and fixes #PROD-456.';
      const mentions = service.parseMentions(body);

      expect(mentions.users).toEqual([]);
      expect(mentions.issues).toEqual(['ENG-123', 'PROD-456']);
    });

    it('should extract both user and issue mentions', () => {
      const body = 'Hey @alice, this closes #ENG-789 as discussed with @bob.';
      const mentions = service.parseMentions(body);

      expect(mentions.users).toEqual(['alice', 'bob']);
      expect(mentions.issues).toEqual(['ENG-789']);
    });

    it('should handle empty or no mentions', () => {
      expect(service.parseMentions('Just a regular comment')).toEqual({
        users: [],
        issues: []
      });

      expect(service.parseMentions('')).toEqual({
        users: [],
        issues: []
      });
    });

    it('should deduplicate repeated mentions', () => {
      const body = 'Hey @john, @john can you help @john with #ENG-123 and #ENG-123?';
      const mentions = service.parseMentions(body);

      expect(mentions.users).toEqual(['john']);
      expect(mentions.issues).toEqual(['ENG-123']);
    });

    it('should handle mentions in markdown contexts', () => {
      const body = 'See [@alice\'s comment](link) and issue [#ENG-456](link).';
      const mentions = service.parseMentions(body);

      expect(mentions.users).toEqual(['alice']);
      expect(mentions.issues).toEqual(['ENG-456']);
    });
  });

  describe('formatMarkdown', () => {
    it('should preserve markdown formatting', () => {
      const markdown = '**Bold** and *italic* with [link](http://example.com)';
      const formatted = service.formatMarkdown(markdown);

      expect(formatted).toBe(markdown);
    });

    it('should handle code blocks', () => {
      const markdown = 'Here is some code:\n```typescript\nconst x = 1;\n```';
      const formatted = service.formatMarkdown(markdown);

      expect(formatted).toContain('```typescript');
      expect(formatted).toContain('const x = 1;');
    });

    it('should handle inline code', () => {
      const markdown = 'Use `console.log()` to debug.';
      const formatted = service.formatMarkdown(markdown);

      expect(formatted).toBe(markdown);
    });

    it('should handle lists', () => {
      const markdown = '- Item 1\n- Item 2\n  - Nested item';
      const formatted = service.formatMarkdown(markdown);

      expect(formatted).toBe(markdown);
    });

    it('should handle empty or whitespace-only content', () => {
      expect(service.formatMarkdown('')).toBe('');
      expect(service.formatMarkdown('   ')).toBe('   ');
    });
  });
});

